#include<cstdio>
#include<algorithm>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=2e5+10;
struct MO
{
	int l,r,idx;inline bool operator<(const MO &q)const
	{
		int l1=l>>8,l2=q.l>>8;
		return l1!=l2?l1<l2:(l1&1?r>q.r:r<q.r);
	}
}Q[N];int cnt[N],a[N],Mx,cnt2[N],P[N],p,n,m,K[N];bool ans[N];
inline int bnd(const int &k){int l(1),r(p),m;while(l<=r)P[m=(l+r)>>1]<=k?l=m+1:r=m-1;return l-1;}
inline void ins(int x)
{
	if(cnt[x])--cnt2[cnt[x]];++cnt2[++cnt[x]];
	if(cnt[x]>Mx)Mx=cnt[x];
}
inline void del(int x)
{
	if(cnt[x]==Mx&&cnt2[cnt[x]]==1)--Mx;
	--cnt2[cnt[x]--];++cnt2[cnt[x]];
}
inline void Solve()
{
	memset(cnt,0,sizeof(cnt));memset(cnt2,0,sizeof(cnt2));
	rep(1,n,i)P[i]=a[i]=read();std::sort(P+1,P+n+1);p=std::unique(P+1,P+n+1)-P-1;rep(1,n,i)a[i]=bnd(a[i]);
	rep(1,m,i)Q[i].l=read(),Q[i].r=read(),Q[i].idx=i,K[i]=read(); sort(Q+1,Q+m+1);
	
	int L=1,R=0;Mx=0;rep(1,m,i)
	{
		while(L>Q[i].l)ins(a[--L]);while(R<Q[i].r)ins(a[++R]);
		while(L<Q[i].l)del(a[L++]);while(R>Q[i].r)del(a[R--]);
		ans[Q[i].idx]=1ll*Mx*K[Q[i].idx]>=(Q[i].r-Q[i].l+1);
	}
	rep(1,m,i)puts(ans[i]?"YES":"NO");
}
int main(){while(~scanf("%d%d",&n,&m))Solve();}
